"use client";

import { formatINR, formatNumber } from "@/lib/format";
import { EditProductModal } from "./EditProductModal";

export function ProductList({ initialList }: { initialList: any[] }) {
  const [filterCategory, setFilterCategory] = useState("All");
  const [visibleCount, setVisibleCount] = useState(20);
  const [editingProduct, setEditingProduct] = useState<any>(null);

  const categories = ["All", ...Array.from(new Set(initialList.map((p) => p.category).filter(Boolean)))];

  const filteredList = useMemo(() => {
    if (filterCategory === "All") return initialList;
    return initialList.filter((p) => p.category === filterCategory);
  }, [initialList, filterCategory]);

  const visibleList = filteredList.slice(0, visibleCount);


  const deleteProduct = async (id: string, name: string) => {
    if (!confirm(`Are you sure you want to delete ${name}?`)) return;
    const res = await fetch(`/api/products/${id}`, { method: "DELETE" });
    if (res.ok) {
      window.location.reload();
    } else {
      alert("Failed to delete product");
    }
  };

  return (
    <div>
      {editingProduct && <EditProductModal product={editingProduct} onClose={() => setEditingProduct(null)} />}
      <div className="flex items-center gap-4 border-b border-slate-100 p-4">
        <div className="text-sm font-semibold text-slate-700">Filter by Category:</div>
        <select
          value={filterCategory}
          onChange={(e) => {
            setFilterCategory(e.target.value);
            setVisibleCount(20);
          }}
          className="rounded-lg border border-slate-300 px-3 py-1.5 text-sm outline-none focus:border-orange-500"
        >
          {categories.map((c: any) => (
            <option key={c} value={c}>{c}</option>
          ))}
        </select>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead className="bg-slate-50 text-[11px] uppercase tracking-wider text-slate-500">
            <tr>
              <th className="px-5 py-2.5 text-left">Product</th>
              <th className="px-5 py-2.5 text-left">HSN</th>
              <th className="px-5 py-2.5 text-left">Category</th>
              <th className="px-5 py-2.5 text-right">Purchase</th>
              <th className="px-5 py-2.5 text-right">Selling</th>
              <th className="px-5 py-2.5 text-right">GST</th>
              <th className="px-5 py-2.5 text-right">Stock</th>
              <th className="px-5 py-2.5 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {visibleList.map((p) => {
              const low = Number(p.currentStock) <= Number(p.minStockLevel);

              return (
                <tr key={p.id} className="hover:bg-slate-50">
                  <td className="px-5 py-2.5">
                    <div className="font-medium text-slate-900">{p.name}</div>
                    <div className="flex gap-1.5 text-[10px]">
                      {p.trackExpiry && <span className="rounded bg-amber-100 px-1.5 py-0.5 font-bold text-amber-700">EXPIRY</span>}
                      {p.isScheduleH && <span className="rounded bg-rose-100 px-1.5 py-0.5 font-bold text-rose-700">SCH-H</span>}
                    </div>
                  </td>
                  <td className="px-5 py-2.5 font-mono text-xs text-slate-600">{p.hsnCode}</td>
                  <td className="px-5 py-2.5 text-slate-600">{p.category}</td>
                  <td className="px-5 py-2.5 text-right text-slate-700">{formatINR(p.purchasePrice)}</td>

                  <td className="px-5 py-2.5 text-right font-semibold text-slate-900">
                      {formatINR(p.sellingPrice)}
                  </td>

                  <td className="px-5 py-2.5 text-right text-slate-700">{Number(p.gstRate)}%</td>

                  <td className={`px-5 py-2.5 text-right font-bold ${low ? "text-rose-600" : "text-slate-900"}`}>
                      {`${formatNumber(Number(p.currentStock), 1)} ${p.unit}`}
                  </td>

                  <td className="px-5 py-2.5 text-right">
                      <div className="flex justify-end gap-3">
                        <button onClick={() => setEditingProduct(p)} className="text-xs font-bold text-orange-600 hover:text-orange-700">Edit</button>
                        <button onClick={() => deleteProduct(p.id, p.name)} className="text-xs font-bold text-rose-500 hover:text-rose-700">Delete</button>
                      </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>

        {visibleCount < filteredList.length && (
          <div className="p-4 text-center">
            <button
              onClick={() => setVisibleCount((prev) => prev + 20)}
              className="rounded-xl border border-slate-300 bg-white px-6 py-2 text-sm font-semibold text-slate-700 shadow-sm hover:bg-slate-50"
            >
              Load More
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

const GST_RATES = [0, 5, 12, 18, 28];

export function EditProductModal({ product, onClose }: { product: any; onClose: () => void }) {
  const router = useRouter();
  const [form, setForm] = useState({
    name: product.name || "",
    category: product.category || "Grocery",
    hsnCode: product.hsnCode || "",
    unit: product.unit || "PCS",
    purchasePrice: product.purchasePrice || "",
    sellingPrice: product.sellingPrice || "",
    mrp: product.mrp || "",
    gstRate: Number(product.gstRate) || 18,
    minStockLevel: product.minStockLevel || "10",
    currentStock: product.currentStock || "0",
    trackExpiry: product.trackExpiry || false,
    description: product.description || "",
    expiryPeriod: "none",
  });
  const [saving, setSaving] = useState(false);

  async function save() {
    if (!form.name || !form.sellingPrice) return;
    setSaving(true);
    try {
      const res = await fetch(`/api/products/${product.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (data.ok) {
        onClose();
        router.refresh();
      } else alert(data.error || "Failed");
    } finally { setSaving(false); }
  }

  function update<K extends keyof typeof form>(k: K, v: typeof form[K]) {
    setForm((f) => ({ ...f, [k]: v }));
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 p-4 backdrop-blur-sm">
      <div className="w-full max-w-3xl rounded-2xl border border-slate-200 bg-white p-5 shadow-2xl overflow-y-auto max-h-[90vh]">
        <div className="mb-4 flex items-center justify-between border-b pb-3">
          <h3 className="text-lg font-bold text-slate-900">Edit Product: {product.name}</h3>
          <button onClick={onClose} className="rounded-lg p-2 text-slate-400 hover:bg-slate-100 hover:text-slate-700">✕</button>
        </div>
        <div className="grid gap-4 md:grid-cols-3">
          <Field label="Product name *">
            <input value={form.name} onChange={(e) => update("name", e.target.value)} className={INPUT} />
          </Field>
          <Field label="Description">
            <input value={form.description} onChange={(e) => update("description", e.target.value)} className={INPUT} placeholder="Enter description..." />
          </Field>
          <Field label="Category"><input value={form.category} onChange={(e) => update("category", e.target.value)} className={INPUT} /></Field>
          <Field label="HSN Code"><input value={form.hsnCode} onChange={(e) => update("hsnCode", e.target.value)} className={INPUT} /></Field>
          <Field label="Unit"><input value={form.unit} onChange={(e) => update("unit", e.target.value)} className={INPUT} /></Field>
          <Field label="Purchase Price"><input type="number" value={form.purchasePrice} onChange={(e) => update("purchasePrice", e.target.value)} className={INPUT} /></Field>
          <Field label="Selling Price *"><input type="number" value={form.sellingPrice} onChange={(e) => update("sellingPrice", e.target.value)} className={INPUT} /></Field>
          <Field label="MRP"><input type="number" value={form.mrp} onChange={(e) => update("mrp", e.target.value)} className={INPUT} /></Field>
          <Field label="GST %">
            <select value={form.gstRate} onChange={(e) => update("gstRate", Number(e.target.value))} className={INPUT}>
              {GST_RATES.map((r) => <option key={r} value={r}>{r}%</option>)}
            </select>
          </Field>
          <Field label="Min Stock"><input type="number" value={form.minStockLevel} onChange={(e) => update("minStockLevel", e.target.value)} className={INPUT} /></Field>
          <Field label="Current Stock"><input type="number" value={form.currentStock} onChange={(e) => update("currentStock", e.target.value)} className={INPUT} /></Field>
          <label className="flex items-center gap-2 self-end text-sm">
            <input type="checkbox" checked={form.trackExpiry} onChange={(e) => update("trackExpiry", e.target.checked)} className="h-4 w-4 rounded border-slate-300 text-orange-500 focus:ring-orange-500" />
            Track expiry (pharmacy)
          </label>
        </div>
        <div className="mt-6 flex justify-end gap-3 border-t pt-4">
          <button onClick={onClose} className="rounded-xl px-5 py-2 text-sm font-semibold text-slate-600 hover:bg-slate-50">Cancel</button>
          <button onClick={save} disabled={saving || !form.name || !form.sellingPrice} className="rounded-xl bg-gradient-to-r from-orange-500 to-rose-500 px-6 py-2 text-sm font-bold text-white shadow-md disabled:opacity-50 transition hover:scale-[1.02]">
            {saving ? "Saving..." : "Save Changes"}
          </button>
        </div>
      </div>
    </div>
  );
}

const INPUT = "w-full rounded-xl border border-slate-200 bg-slate-50 px-3 py-2 text-sm outline-none focus:border-orange-400 focus:bg-white";

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <div className="mb-1 text-[11px] font-semibold text-slate-600">{label}</div>
      {children}
    </div>
  );
}

import { db } from "@/db";
import { products } from "@/db/schema";
import { getActiveStoreId } from "@/lib/session";
import { eq, and } from "drizzle-orm";

export async function PUT(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const storeId = await getActiveStoreId();
  if (!storeId) return Response.json({ ok: false, error: "No store" }, { status: 400 });

  const { id } = await params;
  const b = await req.json();

  await db
    .update(products)
    .set({
      name: b.name,
      category: b.category,
      hsnCode: b.hsnCode,
      unit: b.unit,
      purchasePrice: String(b.purchasePrice),
      sellingPrice: String(b.sellingPrice),
      mrp: String(b.mrp),
      gstRate: String(b.gstRate),
      minStockLevel: String(b.minStockLevel),
      currentStock: String(b.currentStock),
      trackExpiry: b.trackExpiry,
      description: b.description,
    })
    .where(and(eq(products.id, id), eq(products.storeId, storeId)));

  return Response.json({ ok: true });
}

export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const storeId = await getActiveStoreId();
  if (!storeId) return Response.json({ ok: false, error: "No store" }, { status: 400 });

  const { id } = await params;

  // Soft delete so invoice history doesn't break
  await db
    .update(products)
    .set({ isActive: false })
    .where(and(eq(products.id, id), eq(products.storeId, storeId)));

  return Response.json({ ok: true });
}

import { db } from "@/db";
import { parties } from "@/db/schema";
import { and, asc, eq, gt, sql } from "drizzle-orm";
import Link from "next/link";
import { getActiveStoreId } from "@/lib/session";
import { formatINR } from "@/lib/format";

export const dynamic = "force-dynamic";

export default async function KhataPage() {
  const storeId = (await getActiveStoreId())!;
  const customers = await db
    .select()
    .from(parties)
    .where(and(eq(parties.storeId, storeId), eq(parties.type, "customer")))
    .orderBy(sql`${parties.outstandingBalance} DESC`);

  const suppliers = await db
    .select()
    .from(parties)
    .where(and(eq(parties.storeId, storeId), eq(parties.type, "supplier")))
    .orderBy(asc(parties.name));

  const totalReceivable = customers.reduce((s, c) => s + Math.max(0, Number(c.outstandingBalance)), 0);
  const totalPayable = suppliers.reduce((s, c) => s + Math.max(0, -Number(c.outstandingBalance)), 0);
  const net = totalReceivable - totalPayable;

  const overdueCount = await db
    .select({ count: sql<number>`count(*)::int` })
    .from(parties)
    .where(and(eq(parties.storeId, storeId), eq(parties.type, "customer"), gt(parties.outstandingBalance, "0")));

  return (
    <div className="space-y-6">
      <div className="flex items-end justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-950">Digital Khata 📒</h1>
          <p className="text-sm text-slate-500">Track udhaar from customers and dues to suppliers.</p>
        </div>
      </div>

      <div className="rounded-2xl border border-orange-200 dark:border-orange-900/30 bg-gradient-to-r from-orange-50 via-rose-50 to-amber-50 dark:from-orange-900/10 dark:via-rose-900/10 dark:to-amber-900/10 p-6 shadow-sm">
        <div className="grid gap-4 md:grid-cols-3">
          <div>
            <div className="text-xs font-bold uppercase tracking-wider text-emerald-700 dark:text-emerald-500">Aapko Milenge (Customers owe you)</div>
            <div className="mt-1 text-3xl font-bold text-slate-950 dark:text-white">{formatINR(totalReceivable)}</div>
            <div className="text-xs text-slate-600 dark:text-slate-400">{overdueCount[0]?.count ?? 0} parties pending</div>
          </div>
          <div>
            <div className="text-xs font-bold uppercase tracking-wider text-rose-700 dark:text-rose-500">Aapko Dena Hai (You owe suppliers)</div>
            <div className="mt-1 text-3xl font-bold text-slate-950 dark:text-white">{formatINR(totalPayable)}</div>
            <div className="text-xs text-slate-600 dark:text-slate-400">Across {suppliers.length} suppliers</div>
          </div>
          <div>
            <div className="text-xs font-bold uppercase tracking-wider text-indigo-700 dark:text-indigo-400">Net Position</div>
            <div className={`mt-1 text-3xl font-bold ${net >= 0 ? "text-emerald-600 dark:text-emerald-400" : "text-rose-600 dark:text-rose-400"}`}>
              {net >= 0 ? "+" : ""}{formatINR(net)}
            </div>
            <div className="text-xs text-slate-600 dark:text-slate-400">{net >= 0 ? "You are net receivable ✅" : "You are net payable ⚠"}</div>
          </div>
        </div>
      </div>

      {/* Customers */}
      <Section
        title="Customers on Udhaar"
        sub="Outstanding receivables — send reminders to collect faster."
        items={customers}
        kind="customer"
      />

      {/* Suppliers */}
      <Section
        title="Suppliers"
        sub="Amounts you owe to your suppliers."
        items={suppliers}
        kind="supplier"
      />
    </div>
  );
}

