        {items.length === 0 && <div className="p-8 text-center text-sm text-slate-400">No {kind}s yet</div>}
        {items.map((p) => {
          const bal = Number(p.outstandingBalance);
          const isReceivable = kind === "customer" && bal > 0;
          const isPayable = kind === "supplier" && bal < 0;
          return (
            <Link
              key={p.id}
              href={`/dashboard/khata/${p.id}`}
              className="flex items-center justify-between gap-4 p-4 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
            >
              <div className="flex min-w-0 items-center gap-3">
                <div className={`grid h-11 w-11 shrink-0 place-items-center rounded-full text-sm font-bold text-white ${
                  isReceivable ? "bg-gradient-to-br from-orange-400 to-rose-500" :
                  isPayable ? "bg-gradient-to-br from-purple-500 to-indigo-600" :
                  "bg-gradient-to-br from-slate-400 to-slate-500"
                }`}>
                  {p.name[0]?.toUpperCase()}
                </div>
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <div className="truncate font-semibold text-slate-900 dark:text-white">{p.name}</div>
                    {p.tag && (
                      <span className={`rounded-md px-1.5 py-0.5 text-[10px] font-bold uppercase ${
                        p.tag === "vip" ? "bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400" :
                        p.tag === "defaulter" ? "bg-rose-100 dark:bg-rose-900/30 text-rose-700 dark:text-rose-400" :
                        "bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300"
                      }`}>{p.tag}</span>
                    )}
                  </div>
                  <div className="text-xs text-slate-500 dark:text-slate-400">{p.phone || "—"} {p.city ? `· ${p.city}` : ""}</div>
                </div>
              </div>
              <div className="text-right">
                {bal === 0 ? (
                  <span className="text-xs font-semibold text-slate-400">Settled</span>
                ) : (
                  <>
                    <div className={`text-base font-bold ${isReceivable ? "text-rose-600 dark:text-rose-400" : "text-emerald-600 dark:text-emerald-400"}`}>
                      {formatINR(Math.abs(bal))}
                    </div>
                    <div className="text-[11px] font-semibold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                      {isReceivable ? "Aapko Milenge" : "Aapko Dena Hai"}
                    </div>
                  </>
                )}
              </div>
            </Link>
          );
        })}
      </div>
    </div>
  );
}

import { db } from "@/db";
import { parties, khataEntries, stores } from "@/db/schema";
import { and, desc, eq } from "drizzle-orm";
import Link from "next/link";
import { notFound } from "next/navigation";
import { getActiveStoreId } from "@/lib/session";
import { formatINR, formatDate } from "@/lib/format";
import { KhataAdd } from "./KhataAdd";
import { RemindButton } from "./RemindButton";
import { PartyActions } from "./PartyActions";
import { KhataEntryRow } from "./KhataEntryRow";

export const dynamic = "force-dynamic";

export default async function KhataDetail({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const storeId = (await getActiveStoreId())!;
  const [party] = await db.select().from(parties).where(and(eq(parties.id, id), eq(parties.storeId, storeId))).limit(1);
  if (!party) notFound();
  const entries = await db.select().from(khataEntries).where(eq(khataEntries.partyId, id)).orderBy(desc(khataEntries.entryDate), desc(khataEntries.createdAt));
  const [store] = await db.select().from(stores).where(eq(stores.id, storeId)).limit(1);

  const bal = Number(party.outstandingBalance);

  return (
    <div className="mx-auto max-w-3xl space-y-5">
      <Link href="/dashboard/khata" className="text-sm font-semibold text-slate-600 hover:text-slate-900">← Back to khata</Link>

      <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="grid h-14 w-14 place-items-center rounded-full bg-gradient-to-br from-orange-400 to-rose-500 text-lg font-bold text-white">
              {party.name[0]?.toUpperCase()}
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-950">{party.name}</h1>
              <div className="text-xs text-slate-500">{party.phone || "—"} {party.city ? `· ${party.city}` : ""}</div>
              {party.gstin && <div className="text-xs font-mono text-slate-600">GSTIN: {party.gstin}</div>}
              <PartyActions party={party} />
            </div>
          </div>
          <div className="text-right">
            <div className="text-xs font-bold uppercase tracking-wider text-slate-500">Balance</div>
            <div className={`text-2xl font-bold ${bal > 0 ? "text-rose-600" : bal < 0 ? "text-emerald-600" : "text-slate-700"}`}>
              {bal === 0 ? "Settled ✓" : formatINR(Math.abs(bal))}
            </div>
            <div className="text-[11px] text-slate-500">
              {bal > 0 ? `${party.name} will give you` : bal < 0 ? `You owe ${party.name}` : ""}
            </div>
            {bal > 0 && party.phone && <RemindButton partyId={party.id} amount={bal} name={party.name} phone={party.phone} storeName={store.name} />}
          </div>
        </div>
      </div>

      <KhataAdd partyId={party.id} />

      <div className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm">
        <div className="border-b border-slate-100 p-4">
          <h3 className="text-sm font-bold text-slate-900">Ledger entries</h3>
          <p className="text-[11px] text-slate-500">{entries.length} entries</p>
        </div>
        <div className="divide-y divide-slate-100">
          {entries.map((e) => (
            <KhataEntryRow key={e.id} entry={e} />
          ))}
          {entries.length === 0 && <div className="p-8 text-center text-sm text-slate-400">No entries yet</div>}
        </div>
      </div>
    </div>
  );
}

"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

export function KhataAdd({ partyId }: { partyId: string }) {
  const router = useRouter();
  const [type, setType] = useState<"credit" | "debit">("credit");
  const [amount, setAmount] = useState("");
  const [notes, setNotes] = useState("");
  const [saving, setSaving] = useState(false);

  async function save() {
    if (!amount || Number(amount) <= 0) return;
    setSaving(true);
    try {
      await fetch("/api/khata", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ partyId, type, amount: Number(amount), notes }),
      });
      setAmount("");
      setNotes("");
      router.refresh();
    } finally { setSaving(false); }
  }

  return (
    <div className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
      <h3 className="mb-3 text-sm font-bold text-slate-900">Add entry</h3>
      <div className="flex flex-wrap items-stretch gap-2">
        <div className="flex rounded-xl border border-slate-200 bg-slate-50 p-1">
          <button
            onClick={() => setType("credit")}
            className={`rounded-lg px-3 py-1.5 text-xs font-bold ${type === "credit" ? "bg-rose-500 text-white shadow" : "text-slate-600"}`}
          >Gave (Udhaar)</button>
          <button
            onClick={() => setType("debit")}
            className={`rounded-lg px-3 py-1.5 text-xs font-bold ${type === "debit" ? "bg-emerald-500 text-white shadow" : "text-slate-600"}`}
          >Advance / Jama (Received)</button>
        </div>
        <input
          type="number"
          placeholder="₹ Amount"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="w-32 rounded-xl border border-slate-200 bg-slate-50 px-3 py-2 text-sm font-semibold outline-none focus:border-orange-400 focus:bg-white"
        />
        <input
          placeholder="Notes (optional)"
          value={notes}
          onChange={(e) => setNotes(e.target.value)}
          className="min-w-[140px] flex-1 rounded-xl border border-slate-200 bg-slate-50 px-3 py-2 text-sm outline-none focus:border-orange-400 focus:bg-white"
        />
        <button
          onClick={save}
          disabled={saving || !amount}
          className="rounded-xl bg-gradient-to-r from-orange-500 to-rose-500 px-5 py-2 text-sm font-bold text-white shadow-md hover:scale-[1.02] disabled:opacity-50"
        >
          {saving ? "Saving..." : "+ Add"}
        </button>
      </div>
    </div>
  );
}

import { db } from "@/db";
import { parties } from "@/db/schema";
import { getActiveStoreId } from "@/lib/session";
import { eq, and } from "drizzle-orm";

export async function PUT(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const storeId = await getActiveStoreId();
  if (!storeId) return Response.json({ ok: false, error: "No store" }, { status: 400 });

  const { id } = await params;
  const b = await req.json();

  await db
    .update(parties)
    .set({
      name: b.name,
      phone: b.phone,
      city: b.city,
      gstin: b.gstin,
      type: b.type,
    })
    .where(and(eq(parties.id, id), eq(parties.storeId, storeId)));

  return Response.json({ ok: true });
}

export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const storeId = await getActiveStoreId();
  if (!storeId) return Response.json({ ok: false, error: "No store" }, { status: 400 });

  const { id } = await params;

  // Real delete
  await db
    .delete(parties)
    .where(and(eq(parties.id, id), eq(parties.storeId, storeId)));

  return Response.json({ ok: true });
}

import { db } from "@/db";
import { khataEntries, parties } from "@/db/schema";
import { getActiveStoreId } from "@/lib/session";
import { and, eq, sql } from "drizzle-orm";

export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const storeId = await getActiveStoreId();
  if (!storeId) return Response.json({ ok: false, error: "No store" }, { status: 400 });

  const { id } = await params;

  const [entry] = await db.select().from(khataEntries).where(and(eq(khataEntries.id, id), eq(khataEntries.storeId, storeId))).limit(1);
  if (!entry) return Response.json({ ok: false, error: "Entry not found" }, { status: 404 });

  // Reverse the balance impact
  const delta = entry.type === "credit" ? -Number(entry.amount) : Number(entry.amount);

  await db
    .update(parties)
    .set({ outstandingBalance: sql`${parties.outstandingBalance} + ${delta}` })
    .where(eq(parties.id, entry.partyId!));

  await db.delete(khataEntries).where(eq(khataEntries.id, id));

  return Response.json({ ok: true });
}

export async function PUT(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const storeId = await getActiveStoreId();
  if (!storeId) return Response.json({ ok: false, error: "No store" }, { status: 400 });

  const { id } = await params;
  const body = await req.json() as { amount: number; type: "credit" | "debit"; notes?: string };

  const [entry] = await db.select().from(khataEntries).where(and(eq(khataEntries.id, id), eq(khataEntries.storeId, storeId))).limit(1);
  if (!entry) return Response.json({ ok: false, error: "Entry not found" }, { status: 404 });

  // Reverse the OLD balance impact
  const oldDelta = entry.type === "credit" ? -Number(entry.amount) : Number(entry.amount);

  // Apply the NEW balance impact
  const newDelta = body.type === "credit" ? Number(body.amount) : -Number(body.amount);
  const netDelta = oldDelta + newDelta;

  await db
    .update(parties)
    .set({ outstandingBalance: sql`${parties.outstandingBalance} + ${netDelta}` })
    .where(eq(parties.id, entry.partyId!));

  await db
    .update(khataEntries)
    .set({
      amount: String(body.amount),
      type: body.type,
      notes: body.notes,
    })
    .where(eq(khataEntries.id, id));

  return Response.json({ ok: true });
}

"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

export function EditPartyModal({ party, onClose }: { party: any; onClose: () => void }) {
  const router = useRouter();
  const [type, setType] = useState<"customer" | "supplier">(party.type);
  const [name, setName] = useState(party.name || "");
  const [phone, setPhone] = useState(party.phone || "");
  const [gstin, setGstin] = useState(party.gstin || "");
  const [city, setCity] = useState(party.city || "");
  const [saving, setSaving] = useState(false);

  async function save() {
    if (!name) return;
    setSaving(true);
    try {
      const res = await fetch(`/api/parties/${party.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ type, name, phone, gstin, city }),
      });
      const data = await res.json();
      if (data.ok) {
        onClose();
        router.refresh();
      } else {
        alert(data.error || "Failed");
      }
    } finally { setSaving(false); }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 p-4 backdrop-blur-sm">
      <div className="w-full max-w-md rounded-2xl border border-slate-200 bg-white p-5 shadow-2xl">
        <div className="mb-4 flex items-center justify-between border-b pb-3">
          <h3 className="text-lg font-bold">Edit Party</h3>
          <button onClick={onClose} className="rounded-lg p-2 text-slate-400 hover:bg-slate-100 hover:text-slate-700">✕</button>
        </div>
        <div className="grid gap-4 md:grid-cols-2">
          <div className="md:col-span-2 flex rounded-xl border border-slate-200 bg-slate-50 p-1">
            {(["customer", "supplier"] as const).map((t) => (
              <button key={t} onClick={() => setType(t)} className={`flex-1 rounded-lg px-3 py-1.5 text-xs font-bold uppercase ${type === t ? "bg-white shadow text-orange-700" : "text-slate-500"}`}>{t}</button>
            ))}
          </div>
          <Input placeholder="Name *" value={name} onChange={setName} />
          <Input placeholder="Phone (+91)" value={phone} onChange={setPhone} />
          <Input placeholder="GSTIN (optional)" value={gstin} onChange={setGstin} />
          <Input placeholder="City" value={city} onChange={setCity} />
        </div>
        <div className="mt-6 flex justify-end gap-3 border-t pt-4">
          <button onClick={onClose} className="rounded-xl px-5 py-2 text-sm font-semibold text-slate-600 hover:bg-slate-50">Cancel</button>
          <button
            onClick={save}
            disabled={!name || saving}
            className="rounded-xl bg-gradient-to-r from-orange-500 to-rose-500 px-6 py-2 text-sm font-bold text-white shadow-md disabled:opacity-50 transition hover:scale-[1.02]"
          >
            {saving ? "Saving..." : "Save Changes"}
          </button>
        </div>
      </div>
    </div>
  );
}

function Input({ placeholder, value, onChange }: { placeholder: string; value: string; onChange: (v: string) => void }) {
  return (
    <input
